      try {
        await dispatchApprovedProposal(approved, { channel: 'telegram', telegramChatId: chatId });
        await this.sendMessage(chatId, `🚀 Proposal dispatched for execution.`);
      } catch (dispatchErr: any) {
        await this.sendMessage(chatId, `⚠️ Execution dispatch failed: ${dispatchErr?.message}`);
      }
    }
  }
}

